var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。`,ENG:`that you'll be with him, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called him to your office. He said he'd be here soon.`,TWN:`做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SHIELD_SL_NULL_NULL`,text:{KOREA:`어쩐 일로 부르셨는지, 여쭤봐도 되겠습니까?`,JPN:`どういったご用件か、お伺いしてもよろしいでしょうか？`,ENG:`May I ask why you wanted to see me?`,TWN:`請問這次叫我是有什麼事情嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SHIELD_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SHIELD_SL_NULL_NULL`,text:{KOREA:`......종, 종신계약 말씀입니까?`,JPN:`……しゅ、終身契約と言いましたか？`,ENG:`A... l-lifetime contract?`,TWN:`......終、終身契約是嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SHIELD_SL_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SHIELD_SL_NULL_NULL`,text:{KOREA:`만일 이게 꿈이라면, 전 울면서 탈영할지도 모릅니다.`,JPN:`もしこれが夢なら、目が覚めた私は泣いていることでしょう。そして失意のあまり脱走してしまうかもしれません。`,ENG:`If this is just a dream, then I might go AWOL, crying.`,TWN:`這要是在夢裡我說不定會哭著逃跑。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SHIELD_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SHIELD_SL_NULL_NULL`,text:{KOREA:`하하...... 하긴. 머리가 나빠서 경찰대를 떨어졌었는데......`,JPN:`はは……何しろ私は、頭が悪くて偵察隊の試験にも落ちてますからね……`,ENG:`Hah hah... But then, I was too stupid to pass the entrance exam of Police University.`,TWN:`哈哈......也是。我就是因為太笨，才沒考上警察大學啊......`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SHIELD_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SHIELD_SL_NULL_NULL`,text:{KOREA:`이게 제 머릿 속에서 만들어진 꿈이라면 이런 복잡한 계약조항이 나타날 리 없지 말입니다.`,JPN:`私の頭が作った夢の世界なら、こんな込み入った契約内容が出てくるとは思えません。`,ENG:`There's no way my brain is capable of making up dreams like this, containing so many contract details.`,TWN:`這如果是我腦中在做夢的話，是不會出現這麼複雜的契約條款的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SHIELD_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SHIELD_SL_NULL_NULL`,text:{KOREA:`비록 사회에 적응을 못하고 방황하다가 얼떨결에 다시 총을 잡게 된 거지만, 덕분에 사장님 같은 분 곁에서 일하게 됐으니.`,JPN:`社会に馴染めず、流れに流れて、仕方なくまた銃を取るようになった私ですが、おかげで社長のような方の下で働けるようになりました。`,ENG:`I couldn't adjust to society, so I came back to being a soldier. Now, I'm glad I did because I met you.`,TWN:`我是因為無法適應社會不斷徬徨，糊裡糊塗地重新拿起槍的。但拜這所賜，我才能老闆身邊工作。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SHIELD_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`SHIELD_SL_NULL_NULL`,text:{KOREA:`......바로 이런 게 운명인가 싶습니다.`,JPN:`……こういうのを運命と呼ぶんでしょうかね。`,ENG:`I was probably meant to meet you.`,TWN:`......這就是命運吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SHIELD_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};